var __index = {"config":{"lang":["en"],"separator":"[\\s\\-]+","pipeline":["stopWordFilter"]},"docs":[{"location":"index.html","title":"Wei GENG | \u803f\u4f1f","text":"wei.geng [AT] tum.de <p>I am a doctoral reseacher &amp; Ph.D. candidate under the supervision of Prof. Dr.-Ing. J\u00f6rg Ott at Chair of Connected Mobility, CIT, TUM. My current research interests lie in Edge Computing, Networked Systems.</p>"},{"location":"index.html#-short-bio","title":"\ud83d\udcc4 Short Bio","text":"<p>Before joining TUM, I was fortunate to work under the supervision of Prof. Pan Hui, Prof. Gareth Tyson, and Prof. Dirk Kutscher at HKUST as an M.Phil. student. Before that, I worked as a Research &amp; Development Software Engineer at Huawei Technologies Co., Ltd. with Mr. Jing Liu, Dr. Wei Wang, and Dr. Sui Zhou. I obtained my M.Eng and B.Eng from Fudan University and Harbin Engineering University in 2020 and 2017 respectively. I also have internships in Ant Group Co., Ltd. and eBay Inc..</p>"},{"location":"index.html#-research-interests","title":"\ud83d\udcbb Research Interests","text":"<ul> <li>Information-Centric Networking (ICN)</li> <li>Edge Computing (Offloading, Scheduling, Optimization)</li> <li>Networked Systems (from the perspective of Systems)</li> <li>Programming Languages Runtime Scheduling and Optimization (eg. Golang Runtime)</li> </ul>"},{"location":"index.html#-teaching","title":"\ud83d\udcda Teaching","text":"<p>Winter Term 2024/25 - Master Practical Course: Edge Computing and the Internet of Things (IN2106, IN4261)</p>"},{"location":"index.html#-working-experience","title":"\ud83d\udcbc Working Experience","text":"<ul> <li>Fulltime Software Engineer - Huawei Technologies Co., Ltd., Shanghai, China - 2020~2022</li> <li>Intern - Ant Group Co., Ltd., Hangzhou, China - Winter, 2018</li> <li>Intern - eBay Inc., Shanghai, China - Summer, 2019</li> </ul>"},{"location":"index.html#-education","title":"\ud83c\udf93 Education","text":"<ul> <li>M.Phil. - The Hong Kong University of Science and Technology, Guangzhou, China - 2022.9~2024.10</li> <li>M.Eng. - Fudan University, Shanghai, China - 2017~2020</li> <li>B.Eng. - Harbin Engineering University, Harbin, China - 2013~2017</li> </ul>"},{"location":"index.html#-hobbies","title":"\ud83c\udff8 Hobbies","text":"<ul> <li>Basketball, Badminton, Ping-pong.</li> <li>Chinese Calligraphy</li> </ul>"},{"location":"blog.html","title":"Blogs, Notes, Tutorials, and Resources","text":"<ul> <li>CCF DDLs: a open-source project to collect and share the CCF DDLs.</li> <li>Weboard: A lightweight and simple webpage for old devices utilizing their diplays</li> </ul>"},{"location":"confddl.html","title":"Conf DDL","text":""},{"location":"confddl.html#computer-graphics-and-multimedia","title":"Computer Graphics and Multimedia","text":"<ul> <li>ACM SIGGRAPH </li> <li>2023-01-25</li> <li>IEEE VR 2024 </li> <li>Oct 4 2023</li> <li>ACM MM</li> <li>2023-05-04</li> </ul>"},{"location":"confddl.html#artifical-intelligence-and-computer-vision","title":"Artifical Intelligence and Computer Vision","text":"<ul> <li>NeurIPS</li> <li>May 18 2023 Passed</li> <li>IEEE CVPR</li> <li>Nov 10 2023</li> <li>IEEE ICCV </li> <li>Mar 9<sup>th</sup> 2023 Passed</li> <li>ECCV</li> <li>2022-03-07</li> <li>ICML</li> <li>Jan 27<sup>th</sup> 2023, Passed</li> <li>IJCAI </li> <li>Jan 19<sup>th</sup> 2023, Passed</li> </ul>"},{"location":"confddl.html#networking-and-systems","title":"Networking and Systems","text":"<ul> <li>ACM ICN</li> <li>June 19<sup>th</sup> 2023</li> <li>ACM SIGCOMM</li> <li>2023-02-15</li> <li>USENIX NSDI</li> <li>2023-04-27</li> </ul>"},{"location":"confddl.html#hci-and-mixed","title":"HCI and Mixed","text":"<ul> <li>ACM CHI </li> <li>2023-09-14</li> <li>ACM UbiComp/ISWC </li> <li>2023-11-15 </li> <li>Supposed in Feb</li> </ul>"},{"location":"confddl.html#references","title":"References","text":"<p>CCF DDL Website</p>"},{"location":"news.html","title":"News","text":"News <p> 2024-3: Glad to visit Technische Universit\u00e4t Munich.  2024-2: Glad to visit Politecnico di Milano.  2023-09-04: Honored to be selected to receive an ACM Travel Grant and an RBM Research Travel Grant. 2023-08-16: Glad to become a reviewer for ACM ICN 2023 Poster and Demo Track. 2023-08-07: We got an accepted paper in ACM ICN 2023."}]}